import{St as e,j as t,k as n}from"./C2wy_3lr.js";import"./CT0T0Gak.js";import"./cry5Dbjr.js";var r={title:`DREAMER Study Visit at STUBA, Slovakia - Interim Report`,date:`24.05.2025`,categories:[`events`],published:!0},{title:i,date:a,categories:o,published:s}=r,c=t(`<p>The final two days of our DREAMER study visit have come to an end, wrapping up an inspiring and knowledge-packed event!</p> <p>We had the pleasure of hosting a presentation from <strong>Adam Filo - the former project manager of the BIDs Zwirn development</strong>, who shared valuable insights from his experience leading this transformative project.</p> <p>We were also honoured to welcome <strong>Peter Mikoláš, PMP – President of PMI Slovakia Chapter</strong> – who joined us for an engaging discussion on professional project management practices.</p> <p>Throughout the visit, we continued discussions on the development of the educational module within the DREAMER project, including content structure, delivery formats, and collaborative teaching approaches.</p> <p>To top it off, our group visited EIT Manufacturing in Vienna, where we explored the features of cross-border innovation projects and learned about the specific challenges of managing such initiatives.</p> <p>Thank you to all speakers, participants, and partners who made these days so impactful!</p>`,1);function l(t){var r=c();e(10),n(t,r)}export{l as default,r as metadata};